<?php
require_once __DIR__ . '/../includes/library.php';
require_once __DIR__ . '/../includes/media_delivery.php';
require_once __DIR__ . '/../includes/revenue_access_governance.php';
sf_revenue_guard_json_write('audio_tracking',240,900);$data=sf_request_json();$songId=sf_int_from_request($data,'song_id');$eventType=strtolower(trim((string)($data['event_type']??'play')));$allowed=['play','pause','seek','progress','complete','skip','replay','error'];if(!in_array($eventType,$allowed,true))$eventType='play';if($songId<=0)sf_json_response(['ok'=>false,'error'=>'song_id_required'],422);$record=sf_media_song_record($songId);if(!$record)sf_json_response(['ok'=>false,'error'=>'song_not_found'],404);$full=sf_media_user_can_access('song',$record,'full');$preview=sf_media_user_can_access('song',$record,'preview');if(!$full&&!$preview)sf_json_response(['ok'=>false,'error'=>'access_denied'],403);$metrics=sf_revenue_tracking_metrics('song',$songId,$record,$eventType,max(0,sf_int_from_request($data,'position_seconds')),max(0,sf_int_from_request($data,'seconds_played')),max(0,min(100,sf_float_from_request($data,'percent_complete'))),$full);$source=substr((string)($data['source_page']??($_SERVER['HTTP_REFERER']??'')),0,120);$userId=sf_current_user_id();$session=sf_session_key();$pdo=sf_db();if(!$pdo)sf_json_response(['ok'=>true,'stored'=>false,'mode'=>'no_database_configured']);
try{$pdo->beginTransaction();$stmt=$pdo->prepare('INSERT INTO audio_play_events (user_id,song_id,session_key,event_type,position_seconds,seconds_played,percent_complete,source_page,ip_hash,user_agent_hash) VALUES (?,?,?,?,?,?,?,?,?,?)');$stmt->execute([$userId,$songId,$session,$metrics['event_type'],$metrics['position_seconds'],$metrics['seconds_delta'],$metrics['percent_complete'],$source,sf_client_hash($_SERVER['REMOTE_ADDR']??null),sf_client_hash($_SERVER['HTTP_USER_AGENT']??null)]);if($userId&&!empty($metrics['eligible_for_member_progress'])){$progress=$pdo->prepare("INSERT INTO user_song_progress (user_id,song_id,last_position_seconds,total_seconds_played,play_count,completed_count,last_event_type,last_played_at) VALUES (?,?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE last_position_seconds=VALUES(last_position_seconds),total_seconds_played=total_seconds_played+VALUES(total_seconds_played),play_count=play_count+VALUES(play_count),completed_count=completed_count+VALUES(completed_count),last_event_type=VALUES(last_event_type),last_played_at=NOW()");$progress->execute([$userId,$songId,$metrics['position_seconds'],$metrics['seconds_delta'],$metrics['event_type']==='play'?1:0,$metrics['event_type']==='complete'?1:0,$metrics['event_type']]);$item=sf_library_catalog_item('song',$songId,$metrics['event_type']==='complete'?'completed':'saved',['progress_percent'=>(int)round($metrics['percent_complete']),'position_seconds'=>$metrics['position_seconds'],'metadata'=>['last_event_type'=>$metrics['event_type']]]);if($item)sf_library_save_item((int)$userId,$item);}$pdo->commit();sf_json_response(['ok'=>true,'stored'=>true,'verified'=>true,'full_access'=>$full,'metrics'=>$metrics]);}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();error_log('Audio tracking failed: '.$e->getMessage());sf_json_response(['ok'=>false,'error'=>'tracking_failed'],500);}
